function solve(grid: number[][], k: number): number {
    const m = grid.length;
    const n = grid[0].length;

    // Preprocess teleport map
    const teleportMap: (number[][])[] = [];
    for (let i = 0; i < m; i++) {
        teleportMap[i] = [];
        for (let j = 0; j < n; j++) {
            const currentVal = grid[i][j];
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (grid[x][y] <= currentVal) {
                        teleportMap[i][j].push([x, y]);
                    }
                }
            }
        }
    }

    // Dijkstra's algorithm
    const INF = Infinity;
    const dist: number[][][] = new Array(m);
    for (let i = 0; i < m; i++) {
        dist[i] = new Array(n);
        for (let j = 0; j < n; j++) {
            dist[i][j] = new Array(k + 1).fill(INF);
        }
    }
    dist[0][0][0] = 0;

    // Priority queue
    class MinHeap {
        private heap: [number, number, number, number][];
        constructor() {
            this.heap = [];
        }
        push(value: [number, number, number, number]) {
            this.heap.push(value);
            this.heapifyUp(this.heap.length - 1);
        }
        pop(): [number, number, number, number] {
            if (this.heap.length === 0) return [0, 0, 0, 0];
            const result = this.heap[0];
            this.heap[0] = this.heap[this.heap.length - 1];
            this.heap.pop();
            this.heapifyDown(0);
            return result;
        }
        private heapifyUp(index: number) {
            let parent = Math.floor((index - 1) / 2);
            while (index > 0 && this.heap[index][0] < this.heap[parent][0]) {
                [this.heap[index], this.heap[parent]] = [this.heap[parent], this.heap[index]];
                index = parent;
                parent = Math.floor((index - 1) / 2);
            }
        }
        private heapifyDown(index: number) {
            let smallest = index;
            const left = 2 * index + 1;
            const right = 2 * index + 2;
            if (left < this.heap.length && this.heap[left][0] < this.heap[smallest][0]) {
                smallest = left;
            }
            if (right < this.heap.length && this.heap[right][0] < this.heap[smallest][0]) {
                smallest = right;
            }
            if (smallest !== index) {
                [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                this.heapifyDown(smallest);
            }
        }
        get size(): number {
            return this.heap.length;
        }
    }

    const heap = new MinHeap();
    heap.push([0, 0, 0, 0]);

    while (heap.size > 0) {
        const [cost, i, j, t] = heap.pop();

        // Check if we have reached the destination
        if (i === m - 1 && j === n - 1) {
            return cost;
        }

        // If the current cost is higher than the stored distance, skip
        if (cost > dist[i][j][t]) {
            continue;
        }

        // Move right
        if (j + 1 < n) {
            const newCost = cost + grid[i][j + 1];
            if (newCost < dist[i][j + 1][t]) {
                dist[i][j + 1][t] = newCost;
                heap.push([newCost, i, j + 1, t]);
            }
        }

        // Move down
        if (i + 1 < m) {
            const newCost = cost + grid[i + 1][j];
            if (newCost < dist[i + 1][j][t]) {
                dist[i + 1][j][t] = newCost;
                heap.push([newCost, i + 1, j, t]);
            }
        }

        // Teleport if possible
        if (t < k) {
            for (const [x, y] of teleportMap[i][j]) {
                const newT = t + 1;
                if (cost < dist[x][y][newT]) {
                    dist[x][y][newT] = cost;
                    heap.push([cost, x, y, newT]);
                }
            }
        }
    }

    return -1; // If no path found, though problem says there is one
}
